"use strict";(self.webpackChunkdocusaurus=self.webpackChunkdocusaurus||[]).push([[2817],{7969:(e,i,a)=>{a.r(i),a.d(i,{assets:()=>s,contentTitle:()=>r,default:()=>d,frontMatter:()=>t,metadata:()=>l,toc:()=>c});var n=a(4848),o=a(8453);const t={title:"Relation - Intelligence without representation",date:new Date("2007-09-08T00:00:00.000Z"),authors:["fsferrara"],tags:["history","computer-science","artificial-intelligence","ai","brooks"]},r='Relazione sull\'articolo: "Intelligence without representation"',l={permalink:"/blog/2007/relation-intelligence-without-representation",source:"@site/../public/blog/2007/relation-intelligence-without-representation.md",title:"Relation - Intelligence without representation",description:"Rodney A. Brooks",date:"2007-09-08T00:00:00.000Z",tags:[{inline:!1,label:"History",permalink:"/blog/tags/history",description:"history"},{inline:!0,label:"computer-science",permalink:"/blog/tags/computer-science"},{inline:!0,label:"artificial-intelligence",permalink:"/blog/tags/artificial-intelligence"},{inline:!0,label:"ai",permalink:"/blog/tags/ai"},{inline:!0,label:"brooks",permalink:"/blog/tags/brooks"}],readingTime:6.805,hasTruncateMarker:!0,authors:[{name:"Saverio Ferrara",title:"Software Engineer",url:"https://github.com/fsferrara",page:{permalink:"/blog/authors/fsferrara"},socials:{x:"https://x.com/fsferrara",linkedin:"https://www.linkedin.com/in/fsferrara/",github:"https://github.com/fsferrara"},imageURL:"https://github.com/fsferrara.png",key:"fsferrara"}],frontMatter:{title:"Relation - Intelligence without representation",date:"2007-09-08T00:00:00.000Z",authors:["fsferrara"],tags:["history","computer-science","artificial-intelligence","ai","brooks"]},unlisted:!1,prevItem:{title:"Relation - On Representations of Problems of Reasoning about Actions",permalink:"/blog/2007/relation-on-representations-of-problems-of-reasoning-about-actions"},nextItem:{title:"Principali caratteristiche di un sistema Linux con kernel aggiornato alla versione 2.6.X",permalink:"/blog/2006/linux-2_6-features"}},s={authorsImageUrls:[void 0]},c=[{value:"Intelligenza incrementale",id:"intelligenza-incrementale",level:2},{value:"Decomposizione in base alle funzioni",id:"decomposizione-in-base-alle-funzioni",level:2},{value:"Decomposizione in base alle attivit\xe0",id:"decomposizione-in-base-alle-attivit\xe0",level:2},{value:"Limiti dell&#39;approccio descritto",id:"limiti-dellapproccio-descritto",level:2},{value:"Conclusioni",id:"conclusioni",level:2}];function u(e){const i={h2:"h2",li:"li",ol:"ol",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(i.p,{children:"Rodney A. Brooks"}),"\n",(0,n.jsx)(i.p,{children:"Il campo dell'intelligenza artificiale part\xec con l'intento di replicare l'intelligenza umana in una macchina, ma negli anni a seguire sono stati fatti pochi progressi. Nessuno parla di replicare l'intelligenza umana interamente, ma si sono specializzati vari campi come quello della rappresentazione della conoscenza, e la comprensione del linguaggio naturale; i sognatori specializzati nel campo dell'intelligenza artificiale sperano che in futuro tutti questi campi di studio si fondino creando cos\xec dei sistemi veramente intelligenti. Brooks non crede che l'intelligenza umana sia completamente replicabile poich\xe9 troppo complessa; bisognerebbe decomporla in vari sottomoduli, tutti interconnessi tra loro: Brooks usa proprio questo approccio per studiare creature semplici."}),"\n",(0,n.jsx)(i.p,{children:"In questo articolo, risultato di una ricerca effettuata al M.I.T., Brooks illustra il suo approccio di costruire creature intelligenti non basate sulla rappresentazione, capaci di operare in modo autonomo (senza supervisione) nel proprio ambiente. Queste creature sono state costruite in modo incrementale, aggiungendo capacit\xe0 nuove gradualmente; i vantaggi di questo approccio sono:"}),"\n",(0,n.jsxs)(i.ul,{children:["\n",(0,n.jsx)(i.li,{children:"Avere un sistema intelligente gi\xe0 dalle prime fasi;"}),"\n",(0,n.jsx)(i.li,{children:"Concentrarsi solo sulla funzionalit\xe0 (modulo) che si sta progettando;"}),"\n",(0,n.jsx)(i.li,{children:"Semplicit\xe0 di interconnettere i moduli tra loro mediante interfacce."}),"\n"]}),"\n",(0,n.jsx)(i.p,{children:"Brooks inoltre osserva come gli essere viventi sulla terra si sono evoluti. In particolare pone in risalto il fatto che per molto tempo la terra \xe8 stata popolata da organismi \"poco\" intelligenti, e solo ultimamente si sono evoluti. In un certo senso paragona lo studio dell'intelligenza artificiale a come si sono realmente evoluti gli esseri viventi; c'\xe8 un lungo tempo iniziale impiegato a costruire le fondamenta dell'intelligenza, susseguito da un'improvvisa evoluzione. Durante la storia dell'intelligenza artificiale, essa \xe8 stata capace di risolvere vari problemi con appositi algoritmi, ma il pi\xf9 delle volte sono stati dei \"successi\" negati all'AI perch\xe9 ritenuti problemi non strettamente legati all'intelligenza artificiale. D'altro canto non si \xe8 mai parlato di gravi \"fallimenti\" nell'intelligenza artificiale."}),"\n",(0,n.jsx)(i.p,{children:"Brooks pensa che i ricercatori di intelligenza artificiale si ingannano da soli non usando bene l'astrazione. Ad esempio una sedia pu\xf2 essere considerata come un semplice oggetto dove qualcuno di pu\xf2 sedere. Possono anche essere considerate la dimensione, il colore, la consistenza, e tantissime altre particolarit\xe0: la scelta delle caratteristiche \"importanti\" \xe8 data all'astrazione. Cos\xec che i sistemi di intelligenza artificiali hanno in input un insieme limitato di asserzioni che rappresentano il mondo esterno e lo stato interno; queste asserzioni per\xf2 non riescono a descrivere il mondo nei minimi particolari, e il sistema intelligente lavora in un ambiente che non riproduce, dunque, il mondo reale alla perfezione. Il livello di dettaglio \xe8 dettato appunto dall'astrazione fatta dal costruttore del sistema."}),"\n",(0,n.jsx)(i.h2,{id:"intelligenza-incrementale",children:"Intelligenza incrementale"}),"\n",(0,n.jsx)(i.p,{children:'Nel costruire le sue "creature", Brooks non si basa sul comportamento degli umani (anche se afferma che gli umani, assieme agli altri esseri viventi, sono interessanti oggetti di studio), ma da via libera alla sua immaginazione. In particolare definisce un approccio ingegneristico per costruire le sue creature tenendo presente quattro punti fondamentali:'}),"\n",(0,n.jsxs)(i.ol,{children:["\n",(0,n.jsx)(i.li,{children:"Una creatura deve saper far fronte, in modo ragionevole, i cambiamenti del suo ambiente (dinamico);"}),"\n",(0,n.jsx)(i.li,{children:'Una creatura deve essere robusta rispetto al suo ambiente: un piccolo cambiamento del suo "mondo" non deve portare ad un totale collasso del suo comportamento;'}),"\n",(0,n.jsx)(i.li,{children:"Una creatura pu\xf2 avere pi\xf9 scopi da perseguire, ed in base alle circostanze sceglie quale perseguire;"}),"\n",(0,n.jsx)(i.li,{children:"Una creatura deve avere almeno uno scopo da perseguire."}),"\n"]}),"\n",(0,n.jsx)(i.p,{children:"Per rispettare questi quattro punti, c'\xe8 bisogno di decomporre un sistema complesso in pi\xf9 parti, e per fare ci\xf2 si possono seguire due strade: decomposizione in base alle funzioni, e decomposizione in base alle attivit\xe0."}),"\n",(0,n.jsx)(i.h2,{id:"decomposizione-in-base-alle-funzioni",children:"Decomposizione in base alle funzioni"}),"\n",(0,n.jsx)(i.p,{children:"La decomposizione in base alle funzioni il tipo di decomposizione tradizionale, con un sistema centrale che prende in input una descrizione simbolica del mondo da moduli percettivi, e effettua azioni mediante moduli di azione. E' chiaro che il sistema centrale non \xe8 altro che un elaboratore simbolico. La costruzione dei moduli percettivi \xe8 quella del sistema centrale, e quella dei moduli di azione \xe8 fatta spesso da gruppi di ricerca diversi, spesso anche in diversi laboratori."}),"\n",(0,n.jsx)(i.p,{children:'Il sistema centrale \xe8 a sua volta suddiviso in piccole parti, ad esempio "rappresentazione della conoscenza", learning", "ragionamento", ed altri. Un gruppo di lavoro lavoro ad uno di questi moduli specificando gli input e gli output richiesti dal modulo stesso.'}),"\n",(0,n.jsx)(i.p,{children:"Brooks non pensa che questo tipo di decomposizione sia ottimale per vari motivi, tra i pi\xf9 evidenti:"}),"\n",(0,n.jsxs)(i.ul,{children:["\n",(0,n.jsx)(i.li,{children:"C'\xe8 poca speranza per un modulo costruito indipendentemente di trovare posto in un sistema intelligente completo;"}),"\n",(0,n.jsx)(i.li,{children:"L'azione scatenata da una percezione \xe8 connessa da una lunga catena di moduli interconnessi;"}),"\n",(0,n.jsx)(i.li,{children:"Per testare l'effettivo funzionamento di un modulo abbiamo bisogno di tutti gli altri, e sar\xe0 difficile individuare malfunzionamenti."}),"\n"]}),"\n",(0,n.jsx)(i.h2,{id:"decomposizione-in-base-alle-attivit\xe0",children:"Decomposizione in base alle attivit\xe0"}),"\n",(0,n.jsx)(i.p,{children:'Un altro modo di decomporre un sistema complesso \xe8 in base alle attivit\xe0; questo modo di operare non prevede distinzione tra moduli periferici e sistema centrale. Ogni modulo (anche chiamato "strato" - layer) collega direttamente una percezione all\'azione: uno strato in effetti descrive un modello di interazione con il mondo esterno.'}),"\n",(0,n.jsx)(i.p,{children:'La maggior parte di questo articolo si basa proprio su questo approccio, in quanto ha il vantaggio di costruire sistemi (creature) in modo incrementale, aggiungendo nuovi strati agli strati gi\xe0 presenti. Si fa l\'esempio di una creatura molto semplice, capace di evitare oggetti lanciati, e di non "inciampare" su ostacoli imprevisti. Una possibile scomposizione in attivit\xe0 di questa creatura \xe8 di avere due strati, uno che provvede ad evitare gli oggetti, ed un altro che riesce ad evitare ostacoli imprevisti. Il fatto di avere pi\xf9 stati fa si che variazioni del mondo esterno non portino ad un totale collasso del sistema.'}),"\n",(0,n.jsx)(i.p,{children:"La chiave di questo approccio \xe8 che non c'\xe8 una fonte centrale di rappresentazione! Ogni strato \xe8 indipendente e persegue il suo obiettivo, e nel complesso un sistema pu\xf2 avere pi\xf9 obiettivi. Un osservatore esterno vede che la creatura si comporta in modo coerente, ma in realt\xe0 il suo comportamento \xe8 il risultato di insieme di varie interazioni tra gli strati. Minsky da un simile descrizione di come \xe8 generato il comportamento degli umani.\nPer costruire le sue creature Brooks usa una precisa metodologia della quale risalta i punti pi\xf9 importanti:"}),"\n",(0,n.jsxs)(i.ul,{children:["\n",(0,n.jsx)(i.li,{children:"Mai semplificare i dettagli del mondo: anche se in futuro si pensa di adattare la creatura nel mondo reale, ci pu\xf2 essere qualche strato che si basa sulle ipotesi semplificate;"}),"\n",(0,n.jsx)(i.li,{children:"Testare sempre ogni strato accuratamente, e per un lungo periodo nel mondo reale degli umani;"}),"\n",(0,n.jsx)(i.li,{children:"Quando aggiungiamo un nuovo strato, trovare un errore \xe8 pi\xf9 semplice; infatti i vecchi strati sono tutti ben testati, quindi l'errore si trova nel nuovo stato oppure nel modo in cui esso interagisce con gli altri."}),"\n"]}),"\n",(0,n.jsx)(i.h2,{id:"limiti-dellapproccio-descritto",children:"Limiti dell'approccio descritto"}),"\n",(0,n.jsx)(i.p,{children:'Seguendo questi punti chiave sono state costruite quattro creature (robot), che riescono ad operare nel mondo reale con gli umani. Queste creature hanno un massimo di tre strati; nelle simulazioni si \xe8 riusciti ad avere fino a sei strati paralleli, ma quanti strati si possono realmente avere? Il prossimo obiettivo \xe8 costruire una creatura capace di riconoscere le lattine vuote sulle scrivanie degli uffici, e riportarle in un deposito centrale. Per fare ci\xf2 si ha bisogno di molti strati: una possibile scomposizione \xe8 "evitare oggetti", "seguire le pareti", "riconoscere e usare le porte", "riconoscere le scrivanie", "riconoscere le lattine", ed altri. Ovviamente tutti questi strati devono essere coordinati senza l\'ausilio di un sistema di controllo centrale.'}),"\n",(0,n.jsx)(i.p,{children:"Un altro punto interrogativo in questo approccio \xe8 riuscire ad avere sistemi con funzioni ad alto livello come l'apprendimento. Per adesso si \xe8 trovata una strada per aggiungere al sistema uno strato capace di \"imparare dall'istinto\" come ad esempio una farfalla riesce a distinguere un fiore dagli altri, ma \xe8 ancora poco."}),"\n",(0,n.jsx)(i.h2,{id:"conclusioni",children:"Conclusioni"}),"\n",(0,n.jsx)(i.p,{children:"La rappresentazione \xe8 stato il nodo centrale dell'intelligenza artificiale per almeno quindici anni; durante questa ricerca si \xe8 giunto ad un inaspettato risultato: nei modelli semplici di intelligenza la rappresentazione esplicita fa funzionare il sistema, ma non \xe8 l'astrazione giusta per costruire la parte portante del sistema intelligente. La decomposizione in base alle attivit\xe0 e l'approccio incrementale rappresentano il giusto approccio? I risultati si vedranno con il tempo e i risultati degli esperimenti nel mondo reale."})]})}function d(e={}){const{wrapper:i}={...(0,o.R)(),...e.components};return i?(0,n.jsx)(i,{...e,children:(0,n.jsx)(u,{...e})}):u(e)}},8453:(e,i,a)=>{a.d(i,{R:()=>r,x:()=>l});var n=a(6540);const o={},t=n.createContext(o);function r(e){const i=n.useContext(t);return n.useMemo((function(){return"function"==typeof e?e(i):{...i,...e}}),[i,e])}function l(e){let i;return i=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:r(e.components),n.createElement(t.Provider,{value:i},e.children)}}}]);